		REP(k, MAXLOG2 - 1) {

			REP(i, N) {

				if (parent[i][k] < 0) parent[i][k + 1] = -1;

				else parent[i][k + 1] = parent[parent[i][k]][k];

			}

		}

		return;

	}



	//get least common ancestor

